import { makeObservable, observable, computed, action } from "mobx"

class Doubler {
    value

    constructor(value) {
				// 클래스 내부에는 value라는 프로퍼티가 있고, 이값을 구독가능하게 만듦

        makeObservable(this, {
            value: observable,

						// double은 값을 변경하진 않는다. 하지만 값에 특정 computing을 하여 새로운 값을 만들어내고 그 값을 변수처럼 사용하게 해준다. -> computed를 매핑해줌
            double: computed,

						// increment 메서드는 value값을 변화 시킨다. -> action 매핑해줌
            increment: action
        })
        this.value = value
    }

    get double() {
        return this.value * 2
    }

    increment() {
        this.value++
    }
}

import { makeObservable, observable, computed, action } from "mobx"

class Parent {
    // not overridable
    observable1 = 0

    constructor(value) {
        makeObservable(this, {
            observable1: observable,
            computed1: computed,
            action1: action,
            arrowAction1: action
        })
    }

    // overridable
    get computed1() {
        return this.observable * 2
    }

    // overridable
    action1() {
        this.observable++
    }

    // not overridable
    arrowAction1 = () => {}

    // workaround - not annotated - overridable
    overridableArrowAction1 = action(() => {})
}


// 부모를 확장했기때문에, 기존 메서드를 상속받는다.
class Child extends Parent {
    // new
    observable2 = 0

    constructor(value) {
        makeObservable(this, {
						// 상속받았지만, 이 자식 클래스에서 새로 선언하고 싶다! -> override 매핑하고, 이 클래스에서 다시 선언
            action1: override,
            computed1: override,
            // new fields
            observable2: observable,
            computed2: computed,
            action2: action,
            arrowAction2: action
        })
    }

    // overrides
    get computed1() {
        return super.computed1 * 2
    }

    // overrides
    action1() {
        super.action1()
    }

    // workaround - not annotated - overrides
    overridableArrowAction1 = action(() => {})

    // new
    get computed2() {
        return super.computed1 * 2
    }

    // new
    action2() {
        super.action1()
    }

    // new
    arrowAction2 = () => {}
}

import { makeAutoObservable } from "mobx"

// 다음과 같이 class문법을 사용하지 않아도 mobx를 사용할 수 있다.
function createDoubler(value) {
    return makeAutoObservable({
        value,
        get double() {
            return this.value * 2
        },
        increment() {
            this.value++
        }
    })
}

